import React, { useEffect, useState } from "react";

function MatchList() {
  const [matches, setMatches] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchMatches = async () => {
      setLoading(true);
      try {
        const apiKey = process.env.REACT_APP_CRICAPI_KEY;
        console.log("CRICAPI_KEY from .env:", process.env.REACT_APP_CRICAPI_KEY);
        // Check if the API key is set
        if (!apiKey) {
          console.error("CricAPI key is not set in environment variables.");
          return;
        }
        // Fetching data from CricAPI
        const response = await fetch(`https://api.cricapi.com/v1/cricScore?apikey=${apiKey}`);


        const data = await response.json();

        if (data.status === "success") {
          setMatches(data.data);
        } else {
          console.error("Failed to fetch matches", data);
        }
      } catch (error) {
        console.error("API error:", error);
      } finally {
        setLoading(false);
      }
    };

    fetchMatches();
  }, []);

  return (
    <div>
      <h2>Upcoming Matches</h2>
      {loading ? (
        <p>Loading matches...</p>
      ) : (
        <ul>
          {matches.map((match) => (
            <li key={match.id}>
              {match.t1} vs {match.t2} – {match.status}
            </li>
          ))}
        </ul>
      )}
    </div>
  );
}

export default MatchList;
